input.old_string:
  mkdir -p "${WORKSPACE}/.rebase-ai"
  GITHUB_PROJECT_JSON="$out" OWNER_REPO="$REPO" PROJECT_NUMBER="$PROJECT_NUMBER" PROJECT_NODE_ID="$PROJECT_NODE_ID" node -e "
const fs = require('fs');
const path = process.env.GITHUB_PROJECT_JSON;
const repo = process.env.OWNER_REPO;
const n = Number(process.env.PROJECT_NUMBER);
const nodeId = process.env.PROJECT_NODE_ID;
if (!path || !repo || !Number.isInteger(n) || n < 1 || !nodeId) {
  process.stderr.write('github-project.json: missing repo, project number, or node id\\n');
  process.exit(1);
}
const doc = {
  github: {
    repo,
    labels: ['rebase', 'auto-generated'],
    project: { number: n, node_id: nodeId },
  },
};
fs.writeFileSync(path, JSON.stringify(doc, null, 2) + '\\n', { mode: 0o600 });
"

input.new_string:
  mkdir -p "${WORKSPACE}/.rebase-ai"
  GITHUB_PROJECT_JSON="$out" \
    GITHUB_LABELS_JSON="$GITHUB_LABELS_JSON" \
    OWNER_REPO="$REPO" \
    PROJECT_NUMBER="$PROJECT_NUMBER" \
    PROJECT_NODE_ID="$PROJECT_NODE_ID" \
    node -e "
const fs = require('fs');
const path = process.env.GITHUB_PROJECT_JSON;
const labelsPath = process.env.GITHUB_LABELS_JSON;
const repo = process.env.OWNER_REPO;
const n = Number(process.env.PROJECT_NUMBER);
const nodeId = process.env.PROJECT_NODE_ID;
if (!path || !labelsPath || !repo || !Number.isInteger(n) || n < 1 || !nodeId) {
  process.stderr.write('github-project.json: missing repo, project number, node id, or labels manifest\\n');
  process.exit(1);
}
const labelsDoc = JSON.parse(fs.readFileSync(labelsPath, 'utf8'));
const labels = (labelsDoc.labels || []).map((entry) => entry.name).filter(Boolean);
if (labels.length === 0) {
  process.stderr.write('github-project.json: github-labels.json has no labels\\n');
  process.exit(1);
}
const doc = {
  github: {
    repo,
    labels,
    project: { number: n, node_id: nodeId },
  },
};
fs.writeFileSync(path, JSON.stringify(doc, null, 2) + '\\n', { mode: 0o600 });
"

